UPDATE financial_node_template
SET
    name = #{name},
    type = #{type},
    default_monthly_amount = #{defaultMonthlyAmount},
    default_expected_return = #{defaultExpectedReturn}
WHERE id = #{id}
  AND user_id = #{userId}

