DELETE FROM financial_node_template
WHERE id = #{id}
  AND user_id = #{userId}

mapper.update:
UPDATE financial_node_snapshot
SET monthly_amount = #{monthlyAmount},
    expected_annual_return = #{expectedReturn}
WHERE user_id = #{userId}
          AND template_id = #{templateId}
          AND year = #{year}
          AND month = #{month}

mapper.delete:
DELETE FROM financial_node_snapshot
WHERE user_id = #{userId}
          AND template_id = #{templateId}
          AND year = #{year}
          AND month = #{month}

DELETE FROM flow_snapshot
WHERE user_id = #{userId}
          AND year = #{year}
          AND month = #{month}

mapper.insert:
INSERT INTO flow_snapshot (user_id, from_snapshot_id, to_snapshot_id, year, month, amount)
SELECT ft.user_id, fs_from.id, fs_to.id, #{year}, #{month}, ft.amount FROM flow_template ft
JOIN financial_node_snapshot fs_from ON fs_from.template_id = ft.from_template_id AND fs_from.user_id = ft.user_id AND fs_from.year = #{year} AND fs_from.month = #{month}
JOIN financial_node_snapshot fs_to ON fs_to.template_id = ft.to_template_id AND fs_to.user_id = ft.user_id AND fs_to.year = #{year} AND fs_to.month = #{month}
WHERE ft.user_id = #{userId}
